import React, { useState } from 'react';
import '../styles/MovieForm.css';

const MovieForm = ({ initialData = {}, onSubmit, buttonText }) => {
  const [formData, setFormData] = useState({
    title: initialData.title || '',
    director: initialData.director || '',
    year: initialData.year || '',
    genre: initialData.genre || 'Other',
    rating: initialData.rating || 0,
    status: initialData.status || 'plan to watch',
    review: initialData.review || '',
    posterUrl: initialData.posterUrl || ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const genres = ['Action', 'Comedy', 'Drama', 'Horror', 'Sci-Fi', 'Romance', 'Thriller', 'Documentary', 'Animation', 'Other'];
  const statuses = ['plan to watch', 'watching', 'watched'];

  return (
    <form className="movie-form" onSubmit={handleSubmit}>
      <div className="form-group">
        <label htmlFor="title">Title *</label>
        <input
          type="text"
          id="title"
          name="title"
          value={formData.title}
          onChange={handleChange}
          required
        />
      </div>

      <div className="form-group">
        <label htmlFor="director">Director</label>
        <input
          type="text"
          id="director"
          name="director"
          value={formData.director}
          onChange={handleChange}
        />
      </div>

      <div className="form-row">
        <div className="form-group">
          <label htmlFor="year">Year</label>
          <input
            type="number"
            id="year"
            name="year"
            min="1888"
            max={new Date().getFullYear() + 5}
            value={formData.year}
            onChange={handleChange}
          />
        </div>

        <div className="form-group">
          <label htmlFor="rating">Rating (0-10)</label>
          <input
            type="number"
            id="rating"
            name="rating"
            min="0"
            max="10"
            step="0.1"
            value={formData.rating}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label htmlFor="genre">Genre</label>
          <select id="genre" name="genre" value={formData.genre} onChange={handleChange}>
            {genres.map(genre => (
              <option key={genre} value={genre}>{genre}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label htmlFor="status">Status</label>
          <select id="status" name="status" value={formData.status} onChange={handleChange}>
            {statuses.map(status => (
              <option key={status} value={status}>{status}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="form-group">
        <label htmlFor="posterUrl">Poster URL</label>
        <input
          type="url"
          id="posterUrl"
          name="posterUrl"
          value={formData.posterUrl}
          onChange={handleChange}
        />
      </div>

      <div className="form-group">
        <label htmlFor="review">Review</label>
        <textarea
          id="review"
          name="review"
          rows="4"
          value={formData.review}
          onChange={handleChange}
        />
      </div>

      <button type="submit" className="btn-submit">
        {buttonText || 'Save Movie'}
      </button>
    </form>
  );
};

export default MovieForm;
